package org.example.matrix.services;

import org.junit.jupiter.api.BeforeEach;
import org.junit.jupiter.api.Test;
import org.junit.jupiter.api.extension.ExtendWith;
import io.wcm.testing.mock.aem.junit5.AemContext;
import io.wcm.testing.mock.aem.junit5.AemContextExtension;

import static org.junit.jupiter.api.Assertions.*;

@ExtendWith(AemContextExtension.class)
class OracleServiceImplTest {

    private final AemContext context = new AemContext();
    private OracleServiceImpl oracleService;

    @BeforeEach
    void setUp() {
        // Register the service in the mock OSGi context
        oracleService = context.registerInjectActivateService(new OracleServiceImpl());
    }

    @Test
    void testProphecy() {
        String prophecy = oracleService.getProphecy();
        assertNotNull(prophecy, "The Oracle must speak!");
        assertTrue(prophecy.contains("door"), "Follow the white rabbit...");
    }
}
